#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <omp.h>

#ifdef TIMING
#include "timing.h"

struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;
#endif

#define BLOCK_SIZE 256
#define STR_SIZE 256
#define DEVICE 0
#define HALO 1 

void run(int argc, char** argv);

int rows, cols;
int* data;
int** wall;
int* result;
#define M_SEED 9
int pyramid_height;

void
init(int argc, char** argv)
{
	if(argc==4){
		cols = atoi(argv[1]);
		rows = atoi(argv[2]);
                pyramid_height=atoi(argv[3]);
	}else{
                printf("Usage: dynproc row_len col_len pyramid_height\n");
                exit(0);
        }
	data = new int[rows*cols];
	wall = new int*[rows];
	for(int n=0; n<rows; n++)
		wall[n]=data+cols*n;
	result = new int[cols];

	int seed = M_SEED;
	srand(seed);

	for (int i = 0; i < rows; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            wall[i][j] = rand() % 10;
        }
    }
#ifdef BENCH_PRINT
    for (int i = 0; i < rows; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            printf("%d ",wall[i][j]) ;
        }
        printf("\n") ;
    }
#endif
}

void 
fatal(char *s)
{
	fprintf(stderr, "error: %s\n", s);

}

#define IN_RANGE(x, min, max)   ((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))


int calc_path(int *wall, int *result[2], int rows, int cols, 
	     int pyramid_height, int blockCols, int borderCols)
{
    int src = 1, dst = 0;
    int size = rows * cols;

    for (int t = 0; t < rows-1; t+=pyramid_height) {
        int iteration = (t + pyramid_height > rows - 1) ? rows - 1 - t : pyramid_height;

        // Swap src and dst
        int temp = src;
        src = dst;
        dst = temp;

        int small_block_cols = BLOCK_SIZE - iteration * HALO * 2;

        #pragma omp parallel
        {
            int tid = omp_get_thread_num();
            int nthreads = omp_get_num_threads();

            int blockColsPerThread = (blockCols + nthreads - 1) / nthreads;
            int start_block = tid * blockColsPerThread;
            int end_block = start_block + blockColsPerThread;
            if (end_block > blockCols) end_block = blockCols;

            for (int bx = start_block; bx < end_block; bx++) {

                int blkX = small_block_cols * bx - borderCols;
                int blkXmax = blkX + BLOCK_SIZE - 1;

                // Shared memory emulation: arrays in private memory
                int prev[BLOCK_SIZE];
                int res[BLOCK_SIZE];

                // Load prev from gpuSrc equivalent
                #pragma omp simd
                for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                    int xidx = blkX + tx;
                    if (IN_RANGE(xidx, 0, cols - 1)) {
                        prev[tx] = result[src][xidx];
                    } else {
                        prev[tx] = 0; // or some safe default
                    }
                }

                int validXmin = (blkX < 0) ? -blkX : 0;
                int validXmax = (blkXmax > cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - cols + 1) : BLOCK_SIZE - 1;

                for (int i = 0; i < iteration; i++) {
                    // Compute results for threads in range
                    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                        bool isValid = IN_RANGE(tx, validXmin, validXmax);
                        if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) && isValid) {
                            int W = tx - 1;
                            int E = tx + 1;

                            if (W < validXmin) W = validXmin;
                            if (E > validXmax) E = validXmax;

                            int left = prev[W];
                            int up = prev[tx];
                            int right = prev[E];
                            int shortest = MIN(left, up);
                            shortest = MIN(shortest, right);

                            int index = cols * (t + i) + blkX + tx;
                            int add_val = 0;
                            if (index >= 0 && index < (rows * cols)) {
                                add_val = wall[index];
                            }
                            res[tx] = shortest + add_val;
                        } else {
                            res[tx] = prev[tx];
                        }
                    }
                    // Copy res to prev except on last iteration
                    if (i != iteration - 1) {
                        #pragma omp simd
                        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                            prev[tx] = res[tx];
                        }
                    }
                }

                // Write results back to gpuResults[dst]
                #pragma omp simd
                for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                    int xidx = blkX + tx;
                    if (IN_RANGE(tx, validXmin, validXmax) && IN_RANGE(xidx, 0, cols - 1)) {
                        result[dst][xidx] = res[tx];
                    }
                }
            }
        }
    }
    return dst;
}

int main(int argc, char** argv)
{
    run(argc,argv);
    return EXIT_SUCCESS;
}

void run(int argc, char** argv)
{
    init(argc, argv);

    int borderCols = (pyramid_height)*HALO;
    int smallBlockCol = BLOCK_SIZE-(pyramid_height)*HALO*2;
    int blockCols = cols/smallBlockCol+((cols%smallBlockCol==0)?0:1);

    printf("pyramidHeight: %d\ngridSize: [%d]\nborder:[%d]\nblockSize: %d\nblockGrid:[%d]\ntargetBlock:[%d]\n",\
	pyramid_height, cols, borderCols, BLOCK_SIZE, blockCols, smallBlockCol);

    int size = rows*cols;

    int *gpuResult[2];
    gpuResult[0] = new int[cols];
    gpuResult[1] = new int[cols];

    // Initialize gpuResult[0] with first row of data
    for (int i = 0; i < cols; i++) {
        gpuResult[0][i] = data[i];
    }

    int *gpuWall = data + cols; // pointer to second row onwards in data

#ifdef  TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    int final_ret = calc_path(gpuWall, gpuResult, rows, cols, 
	 pyramid_height, blockCols, borderCols);

#ifdef  TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    // Copy final results row from gpuResult[final_ret]
    for (int i = 0; i < cols; i++) {
        result[i] = gpuResult[final_ret][i];
    }

#ifdef BENCH_PRINT
    for (int i = 0; i < cols; i++)
            printf("%d ",data[i]) ;
    printf("\n") ;
    for (int i = 0; i < cols; i++)
            printf("%d ",result[i]) ;
    printf("\n") ;
#endif

    delete [] gpuResult[0];
    delete [] gpuResult[1];

    delete [] data;
    delete [] wall;
    delete [] result;

#ifdef  TIMING
    printf("Exec: %f\n", kernel_time);
#endif
}
